package arch.day1;

/**
 * Day 1 basic: static reference tables for JDK vs JRE vs JVM.
 * // In real projects javac lives in JDK; java launches HotSpot.
 * // Staff signal: jcmd and javap also live in the JDK — without them
 * //   you cannot attach to a running JVM for GC diagnostics.
 */
public class Day1Basic {

    public static void main(String[] args) {
        System.out.println("=== Java platform layers ===");
        System.out.println("JDK  | Development kit  | javac, jar, javadoc, jdb, jcmd, jlink, JVM + libs");
        System.out.println("JRE  | Runtime bundle   | JVM + class libraries (no javac, no jcmd)");
        System.out.println("JVM  | Execution engine | loads bytecode, verifies, JIT-compiles, GC");
        System.out.println();

        System.out.println("=== Compile vs run commands ===");
        System.out.println("javac Hello.java         -> produces Hello.class bytecode");
        System.out.println("java Hello               -> starts JVM, loads Hello, calls main");
        System.out.println("java Hello.java          -> since Java 11: in-memory compile+run (single file)");
        System.out.println("javap -c Hello.class     -> disassemble bytecode (JDK tool, debugging)");
        System.out.println("jcmd <pid> VM.flags      -> show effective JVM flags at runtime");
        System.out.println();

        System.out.println("=== main() contract: each keyword has a runtime reason ===");
        System.out.println("public static void main(String[] args)");
        System.out.println("  public  -> launcher can invoke without access restrictions");
        System.out.println("  static  -> no instance required before entry; JVM has no object to construct");
        System.out.println("  void    -> no return value to launcher; exit code via System.exit()");
        System.out.println("  args    -> tokens from CLI after class name");
        System.out.println();

        System.out.println("=== Key environment variables ===");
        System.out.println("JAVA_HOME  -> JDK root (Gradle, Maven, IntelliJ read this)");
        System.out.println("PATH       -> shell resolution order; javac wins/loses here");
        System.out.println("CLASSPATH  -> fallback classpath (override with -cp at runtime)");
        System.out.println();

        System.out.println("=== Common prod failures tied to this lesson ===");
        System.out.println("javac missing in CI          -> JRE-only image or PATH lacks JDK/bin");
        System.out.println("ClassNotFoundException       -> classpath or module path wrong");
        System.out.println("UnsupportedClassVersionError -> bytecode newer than runtime JVM");
        System.out.println("NoSuchMethodError: main      -> main typo or wrong modifier");
        System.out.println("VerifyError at class load    -> bad bytecode from code generator (CGLIB/Lombok)");
    }
}

package arch.day1;

/**
 * Day 1 intermediate: four labelled scenarios a Staff engineer narrates.
 * // Real JVM would throw; here we print expected exception class names.
 * // Multi-stage Docker builds use JDK for compile and JRE for the final image.
 */
public class Day1Intermediate {

    static void scenario1() {
        System.out.println("--- Scenario 1: clean compile-and-run narrative ---");
        System.out.println("step A: javac reads .java, resolves types, emits .class bytecode");
        System.out.println("step B: java -cp out Demo starts a new OS process (HotSpot JVM)");
        System.out.println("step C: bytecode verifier accepts stack maps -> no VerifyError");
        System.out.println("step D: static initializers run before main() body");
        System.out.println("step E: main() executes; JIT promotes hot code to native after warmup");
        System.out.println("staff signal: jcmd <pid> VM.flags shows active GC and heap flags");
        System.out.println();
    }

    static void scenario2() {
        System.out.println("--- Scenario 2: wrong working directory (missing classpath root) ---");
        System.out.println("command:  java com.acme.Demo   (cwd does not contain com/acme tree)");
        System.out.println("result:   ClassNotFoundException or NoClassDefFoundError at launch");
        System.out.println("why:      application class loader searches classpath left-to-right");
        System.out.println("          it cannot find com/acme/Demo.class under any entry");
        System.out.println("fix:      cd to classpath root   OR   pass -cp target/classes");
        System.out.println("verify:   java -verbose:class -cp target/classes com.acme.Demo");
        System.out.println("          look for [Loaded com.acme.Demo from ...] in output");
        System.out.println();
    }

    static void scenario3() {
        System.out.println("--- Scenario 3: JRE-only CI image (build fails before tests) ---");
        System.out.println("symptom:  mvnw compile exits 127; log says javac not found in PATH");
        System.out.println("cause:    Dockerfile FROM eclipse-temurin:17-jre (no javac binary)");
        System.out.println("fix:      change to eclipse-temurin:17-jdk for build stage");
        System.out.println("          use multi-stage: JDK for compile, JRE for final image");
        System.out.println("verify:   docker run <image> javac -version  ->  javac 17.x.x");
        System.out.println("staff:    ls $JAVA_HOME/bin | grep javac  inside the container");
        System.out.println();
    }

    static void scenario4() {
        System.out.println("--- Scenario 4: java and javac disagree (JAVA_HOME vs PATH) ---");
        System.out.println("symptom:  java -version prints 21, javac -version prints 17");
        System.out.println("cause:    PATH resolves two JDK installs; Gradle reads JAVA_HOME");
        System.out.println("          Gradle daemon compiled with 17, shell runs 21 launcher");
        System.out.println("fix step 1: type -a java   (bash)  or  where java  (Windows)");
        System.out.println("fix step 2: align JAVA_HOME=<17-root>; export to shell profile");
        System.out.println("fix step 3: reopen terminal; verify both commands agree");
        System.out.println("prevention: Gradle toolchain block pins JDK version in build.gradle");
        System.out.println();
    }

    public static void main(String[] args) {
        scenario1();
        scenario2();
        scenario3();
        scenario4();
    }
}

package arch.day1;

import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

/**
 * Day 1 advanced: deterministic classpath simulation.
 * // Real JVM uses native loaders; this models ordered search.
 */
public class Day1Advanced {

    record ClasspathEntry(String label, boolean containsDemoClass) {}

    static List<String> splitClasspath(String raw) {
        List<String> parts = new ArrayList<>();
        StringBuilder cur = new StringBuilder();
        for (int i = 0; i < raw.length(); i++) {
            char c = raw.charAt(i);
            if (c == ';' || c == ':') {
                parts.add(cur.toString().trim());
                cur.setLength(0);
            } else {
                cur.append(c);
            }
        }
        if (cur.length() > 0) {
            parts.add(cur.toString().trim());
        }
        return parts;
    }

    static String firstHit(List<ClasspathEntry> ordered, String goal) {
        for (ClasspathEntry e : ordered) {
            if (e.containsDemoClass()) {
                return e.label();
            }
        }
        return "NOT_FOUND";
    }

    public static void main(String[] args) {
        System.out.println("=== Block 1: tokenized classpath ===");
        String raw = "out/classes;vendor/lib.jar;extra";
        List<String> tokens = splitClasspath(raw);
        for (int i = 0; i < tokens.size(); i++) {
            System.out.println("entry[" + i + "] = " + tokens.get(i));
        }
        System.out.println();

        System.out.println("=== Block 2: ordered search for Demo.class ===");
        List<ClasspathEntry> entries = List.of(
            new ClasspathEntry("out/classes", true),
            new ClasspathEntry("vendor/lib.jar", false),
            new ClasspathEntry("extra", false)
        );
        String hit = firstHit(entries, "Demo");
        System.out.println("first provider = " + hit);
        System.out.println();

        System.out.println("=== Block 3: launcher triage matrix ===");
        Map<String, String> table = new LinkedHashMap<>();
        table.put("javac missing", "install JDK; add JDK/bin to PATH before JRE shims");
        table.put("java cannot find class", "fix -cp, package directories, or fully-qualified name");
        table.put("UnsupportedClassVersionError", "run with newer JVM or recompile with --release");
        table.put("NoSuchMethodError: main", "check main signature is public static void main(String[])");
        for (Map.Entry<String, String> e : table.entrySet()) {
            System.out.println(e.getKey() + " -> " + e.getValue());
        }
    }
}

