package arch.day1;

/**
 * Day 1 exercise — ties together assignments_phase1.json Day 1 prompts.
 * Demonstrates deterministic output suitable for CI snapshot tests.
 */
public class Day1Exercise {

    public static void main(String[] args) {
        // 1) Lecture card — literal strings only (O(1) output, no collections)
        System.out.println("JDK  -> full kit: javac, tools, libraries");
        System.out.println("JRE  -> runtime: JVM + standard libraries");
        System.out.println("JVM  -> executes bytecode, manages heap + JIT");
        System.out.println("javac-> translates .java sources into .class files");
        System.out.println("java -> launcher that boots a JVM for a class name");
        System.out.println();

        // 2) Execution flow story
        System.out.println("1. Author saves Example.java");
        System.out.println("2. javac produces Example.class bytecode");
        System.out.println("3. java loads bytecode via class loaders");
        System.out.println("4. JVM invokes public static void main");
        System.out.println();

        // 3) Broken PATH scenario — deterministic diagnosis text
        System.out.println("Incident: 'javac' is not recognized");
        System.out.println("Likely cause A: JRE-only install (no javac binary shipped)");
        System.out.println("Likely cause B: JDK bin missing from PATH");
        System.out.println("Post-fix check: run javac -version in the same shell");
        System.out.println();

        // 4) Property card — literals stand in for System.getProperty during lessons
        // Real service code would call System.getProperty(key) for each line.
        System.out.println("java.version = 17.0.9-demo");
        System.out.println("java.vendor = DemoVendor");
        System.out.println("java.home = /demo/jdk-home");
        System.out.println("os.name = DemoOS");
        System.out.println();

        // 5) Version alignment reminder
        System.out.println("Reminder: javac -version and java -version must reference the same JDK home.");
    }
}

